const staticData = $getWorkflowStaticData('global');
const feed = $input.first().json;

const gameState = feed.gameData?.status?.abstractGameState;
const currentPlay = feed.liveData?.plays?.currentPlay;
const linescore = feed.liveData?.linescore;

if (!currentPlay) {
  return [{ json: { has_new_pitch: 0, game_state: gameState, game_pk: feed.gamePk } }];
}

const atBatIdx = currentPlay?.about?.atBatIndex ?? -1;
const pitchEvents = (currentPlay?.playEvents ?? []).filter(e => e.isPitch);
const pitchCount = pitchEvents.length;
const pitchId = `${atBatIdx}-${pitchCount}`;
const lastPitchId = staticData.lastPitchId ?? '';

if (pitchCount === 0 || pitchId === lastPitchId) {
  return [{ json: { has_new_pitch: 0, game_state: gameState, game_pk: feed.gamePk } }];
}

const boxscore = feed.liveData?.boxscore;
const halfInning = currentPlay?.about?.halfInning ?? 'top';
const defSide = halfInning === 'top' ? 'home' : 'away';
const defTeam = boxscore?.teams?.[defSide];

let catcherId = null;
const fielderIds = [];
for (const [, player] of Object.entries(defTeam?.players ?? {})) {
  const posCode = player?.position?.code;
  const id = player?.person?.id;
  if (!id) continue;
  if (posCode === '2') catcherId = id;
  const posNum = parseInt(posCode);
  if (posNum >= 3 && posNum <= 9) fielderIds.push(id);
}

const batSide = currentPlay?.matchup?.batSide?.code ?? 'R';
const pitcherId = currentPlay?.matchup?.pitcher?.id;

if (!staticData.pitchCountByPitcher) staticData.pitchCountByPitcher = {};
if (staticData.lastGamePk !== feed.gamePk) {
  staticData.pitchCountByPitcher = {};
  staticData.lastGamePk = feed.gamePk;
}
if (pitcherId) {
  staticData.pitchCountByPitcher[pitcherId] = (staticData.pitchCountByPitcher[pitcherId] ?? 0) + 1;
}
const pitchCountOverride = pitcherId ? (staticData.pitchCountByPitcher[pitcherId] ?? 0) : 0;

if (!staticData.pitchEffectiveness) staticData.pitchEffectiveness = {};
const latestPitch = pitchEvents[pitchEvents.length - 1];
const pitchType = latestPitch?.details?.type?.code;
const pitchResult = latestPitch?.details?.description ?? '';
const isEffective = ['Swinging Strike', 'Called Strike', 'Foul', 'Foul Tip', 'Swinging Strike (Blocked)'].some(r => pitchResult.includes(r));
if (pitchType && pitcherId) {
  const key = `${pitcherId}_${pitchType}`;
  if (!staticData.pitchEffectiveness[key]) staticData.pitchEffectiveness[key] = { total: 0, effective: 0 };
  staticData.pitchEffectiveness[key].total += 1;
  if (isEffective) staticData.pitchEffectiveness[key].effective += 1;
}

const preGameContext = staticData[`context_${feed.gamePk}`] ?? {};
staticData.lastPitchId = pitchId;

return [{
  json: {
    has_new_pitch: 1,
    game_pk: feed.gamePk,
    at_bat_number: atBatIdx,
    pitch_number: latestPitch?.pitchNumber,
    pitcher_id: pitcherId,
    batter_id: currentPlay?.matchup?.batter?.id,
    catcher_id: catcherId,
    fielder_ids: fielderIds.slice(0, 7),
    inning: linescore?.currentInning,
    balls: currentPlay?.count?.balls,
    strikes: currentPlay?.count?.strikes,
    outs: currentPlay?.count?.outs,
    on_1b: linescore?.offense?.first  ? 1 : 0,
    on_2b: linescore?.offense?.second ? 1 : 0,
    on_3b: linescore?.offense?.third  ? 1 : 0,
    home_score: linescore?.teams?.home?.runs ?? 0,
    away_score: linescore?.teams?.away?.runs ?? 0,
    game_state: gameState,
    bat_side: batSide,
    pitch_count_override: pitchCountOverride,
    pitch_effectiveness: staticData.pitchEffectiveness,
    pre_game_context: preGameContext
  }
}];

