const diffData   = $('투구 diff 감지').item.json;
const prediction = $('FastAPI 투구 예측').item.json;
const aiRaw      = $input.first().json.output ?? '{}';

let ai;
try {
  ai = JSON.parse(aiRaw);
} catch (e) {
  ai = { commentary: aiRaw, reasoning: '', confidence_level: 'low' };
}

return [{
  json: {
    event:           'new_pitch_prediction',
    game_pk:         diffData.game_pk,
    at_bat_number:   diffData.at_bat_number,
    pitch_number:    diffData.pitch_number,
    inning:          diffData.inning,
    count:           `${diffData.balls}B-${diffData.strikes}S`,
    outs:            diffData.outs,
    on_1b:           diffData.on_1b,
    on_2b:           diffData.on_2b,
    on_3b:           diffData.on_3b,
    pitcher_id:      diffData.pitcher_id,
    batter_id:       diffData.batter_id,
    bat_side:        diffData.bat_side,
    predicted_pitch: prediction.predicted_pitch,
    confidence:      prediction.confidence,
    pitch_probabilities: prediction.pitch_probabilities,
    model_used:      prediction.model_used,
    routing:         prediction.routing,
    commentary:      ai.commentary,
    reasoning:       ai.reasoning,
    confidence_level: ai.confidence_level,
    inference_ts:    new Date().toISOString()
  }
}];

const staticData = $getWorkflowStaticData('global');
const payload = $input.first().json;

if (!staticData.prediction_log) staticData.prediction_log = [];

staticData.prediction_log.push({
  game_pk:         payload.game_pk,
  at_bat_number:   payload.at_bat_number,
  pitch_number:    payload.pitch_number,
  predicted_pitch: payload.predicted_pitch,
  confidence:      payload.confidence,
  actual_pitch:    null,
  ts:              payload.inference_ts
});

if (staticData.prediction_log.length > 500) {
  staticData.prediction_log = staticData.prediction_log.slice(-500);
}

return [{ json: { logged: true, total_predictions: staticData.prediction_log.length } }];
